class LFUCache {
    private int capacity;
    private int minFreq;
    private Map<Integer, Integer> values;
    private Map<Integer, Integer> counts;
    private Map<Integer, LinkedHashSet<Integer>> lists;

    public LFUCache(int capacity) {
        this.capacity = capacity;
        this.minFreq = 0;
        values = new HashMap<>();
        counts = new HashMap<>();
        lists = new HashMap<>();
        lists.put(1, new LinkedHashSet<>());
    }

    public int get(int key) {
        if (!values.containsKey(key)) return -1;
        int count = counts.get(key);
        lists.get(count).remove(key);
        if (lists.get(count).isEmpty() && count == minFreq) {
            minFreq++;
        }
        counts.put(key, count + 1);
        lists.computeIfAbsent(count + 1, k -> new LinkedHashSet<>()).add(key);
        return values.get(key);
    }

    public void put(int key, int value) {
        if (capacity <= 0) return;
        if (values.containsKey(key)) {
            values.put(key, value);
            get(key);
            return;
        }
        if (values.size() >= capacity) {
            int evict = lists.get(minFreq).iterator().next();
            lists.get(minFreq).remove(evict);
            values.remove(evict);
            counts.remove(evict);
        }
        values.put(key, value);
        counts.put(key, 1);
        minFreq = 1;
        lists.computeIfAbsent(1, k -> new LinkedHashSet<>()).add(key);
    }
}
